import com.cronutils.utils.Preconditions;

import java.time.DayOfWeek;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.EnumSet;
import java.util.List;
import java.util.Set;

/**
 * Generates matching days for a given year and month for a given day of week cron field with an every expression.
 */
class EveryDayOfWeekValueGenerator extends EveryFieldValueGenerator {
    private final int lastDayOfMonth;
    private int year;
    private int month;
    private final Set<DayOfWeek> dowValidValues;

    EveryDayOfWeekValueGenerator(final CronField cronField, final int year, final int month, WeekDay mondayDoWValue) {
<COVER>        super(cronField);
<COVER>        Preconditions.checkArgument(CronFieldName.DAY_OF_WEEK.equals(cronField.getField()), "CronField does not belong to day of week");
<COVER>        this.year = year;
<COVER>        this.month = month;
<COVER>        final LocalDate date = LocalDate.of(year, month, 1);
<COVER>        lastDayOfMonth = date.lengthOfMonth();

        // from is set by EveryFieldValueGenerator to be the first day of the week to start counting from
        // and to is set by EveryFieldValueGenerator to be the last day of the week
        // in the case of from-to/period (ex. MON-FRI/2)
<COVER>        final Every every = (Every) cronField.getExpression();
<COVER>        int period = every.getPeriod().getValue();
<COVER>        Preconditions.checkArgument(period > 0 && period < 8, "Cron Expression for day of week has an invalid period.");
<COVER>        dowValidValues = getValidDays(mondayDoWValue, period, from, to);
    }

    private static Set<DayOfWeek> getValidDays(WeekDay mondayDoWValue, int period, int from, int to) {
<COVER>        List<DayOfWeek> validDays = new ArrayList<>(7);
<COVER>        for (int day = from; day <= to; day += period) {
            // Convert from cron day of the week to Java DayOfWeek
<COVER>            int javaDay = ConstantsMapper.weekDayMapping(mondayDoWValue, ConstantsMapper.JAVA8, day);
<COVER>            validDays.add(DayOfWeek.of(javaDay));
        }
<COVER>        return EnumSet.copyOf(validDays);
    }

    @Override
    public int generateNextValue(final int reference) throws NoSuchValueException {
        int day = reference;
        do {
            day++;
        } while (!isMatch(day) && day <= lastDayOfMonth);
        if (day > lastDayOfMonth) {
            throw new NoSuchValueException();
        }
        return day;
    }

    @Override
    public int generatePreviousValue(final int reference) throws NoSuchValueException {
        int day = reference;
        do {
            day--;
        } while (!isMatch(day) && day > 0);
        if (day <= 0) {
            throw new NoSuchValueException();
        }
        return day;
    }

    @Override
    protected List<Integer> generateCandidatesNotIncludingIntervalExtremes(int start, int end) {
        // start is the day of month to start from
        List<Integer> candidates = new ArrayList<>();
        int reference = start;
        try {
            while (reference < end) {
                reference = generateNextValue(reference);
                if (reference < end) {
                    candidates.add(reference);
                }
            }
        } catch (NoSuchValueException ignored) {
            // next generated value would be beyond the end of the month, so just ignore it and finish
        }
        return candidates;
    }

    @Override
    public boolean isMatch(final int value) {
        // value is the day of the month
<COVER>        if (value > lastDayOfMonth || value < 1) {
            return false;
        }
<COVER>        DayOfWeek dayOfWeek = LocalDate.of(year, month, value).getDayOfWeek();
<COVER>        return dowValidValues.contains(dayOfWeek);
    }
}

