<COVER>        int daysToWeekend = WeekendPolicy.daysToWeekend(weekendPolicy, startDate);
<COVER>        int daysFromWeekend = WeekendPolicy.daysFromWeekend(weekendPolicy, endDate);
<COVER>        int daysBetween = (int)Duration.between(startDate, endDate).toDays()+1;

        //2+ [xxx+2]/7*5
<COVER>        int tmpWeekdays = (daysBetween-daysToWeekend-daysFromWeekend-2)/7*5;
<COVER>        tmpWeekdays = tmpWeekdays-holidays.size();

<COVER>        return tmpWeekdays+daysToWeekend+daysFromWeekend;
    }

    private static List<ZonedDateTime> holidaysInRange(ZonedDateTime startDate, ZonedDateTime endDate, List<ZonedDateTime> holidays){
<COVER>        if(holidays.isEmpty()){
            return holidays;
        }
<COVER>        int idxstart = findIdx(0, holidays.size()-1, startDate, holidays);
<COVER>        int idxend = findIdx(0, holidays.size()-1, endDate, holidays);
<COVER>        return holidays.subList(idxstart, idxend+1);
