    private static int findIdx(int startidx, int endidx, ZonedDateTime endDate, List<ZonedDateTime> holidays){
<COVER>        if(startidx==endidx){
<COVER>            return startidx;
        }
<COVER>        int pivot = (endidx-startidx)/2;

<COVER>        if(holidays.get(pivot).equals(endDate)){
<COVER>            return pivot;
        }
<COVER>        if(holidays.get(pivot).isBefore(endDate)){
<COVER>            return findIdx(++pivot, endidx, endDate, holidays);
        }else{
            return findIdx(startidx, pivot, endDate, holidays);
        }
    }
}

